import { useState, useEffect } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

function Booking() {
  const [bookings, setBookings] = useState([]);
  const [userName, setUserName] = useState("");
  const [selectedService, setSelectedService] = useState("");

  const navigate = useNavigate();

  const services = [
    { name: "Web Development", icon: "💻" },
    { name: "App Development", icon: "📱" },
    { name: "UI/UX Design", icon: "🎨" },
    { name: "SEO Optimization", icon: "🚀" },
    { name: "Bug Fixing", icon: "🛠️" }
  ];

  const fetchBookings = () => {
    const token = localStorage.getItem("token");

    axios
      .get("http://localhost:5000/api/bookings", {
        headers: {
          Authorization: `Bearer ${token}`
        }
      })
      .then(res => setBookings(res.data));
  };

  useEffect(() => {
    const token = localStorage.getItem("token");
    if (!token) return navigate("/login");
    fetchBookings();
  }, []);

  const bookService = () => {
    const token = localStorage.getItem("token");

    if (!userName || !selectedService) {
      alert("Fill all fields");
      return;
    }

    axios.post(
      "http://localhost:5000/api/bookings",
      {
        userName,
        serviceName: selectedService
      },
      {
        headers: { Authorization: `Bearer ${token}` }
      }
    ).then(() => {
      fetchBookings();
      setUserName("");
      setSelectedService("");
    });
  };

  const logout = () => {
    localStorage.removeItem("token");
    navigate("/login");
  };

  return (
    <div style={styles.page}>

      {/* HEADER */}
      <div style={styles.header}>
        <div>
          <h1 style={styles.title}>Service Booking</h1>
          <p style={styles.sub}>Select a service & manage bookings</p>
        </div>

        <button style={styles.logout} onClick={logout}>
          Logout
        </button>
      </div>

      {/* MAIN */}
      <div style={styles.layout}>

        {/* LEFT */}
        <div style={styles.panel}>
          <h2 style={styles.heading}>New Booking</h2>

          <input
            style={styles.input}
            placeholder="Your Name"
            value={userName}
            onChange={(e) => setUserName(e.target.value)}
          />

          <div style={styles.grid}>
            {services.map((s, i) => (
              <div
                key={i}
                onClick={() => setSelectedService(s.name)}
                style={{
                  ...styles.card,
                  border:
                    selectedService === s.name
                      ? "2px solid #3b82f6"
                      : "1px solid rgba(255,255,255,0.08)"
                }}
              >
                <div style={{ fontSize: "22px" }}>{s.icon}</div>
                <div>{s.name}</div>
              </div>
            ))}
          </div>

          <button style={styles.button} onClick={bookService}>
            Confirm Booking
          </button>
        </div>

        {/* RIGHT */}
        <div style={styles.panel}>
          <h2 style={styles.heading}>Recent Bookings</h2>

          {bookings.length === 0 ? (
            <p style={{ opacity: 0.5 }}>No bookings yet</p>
          ) : (
            bookings.map((b, i) => (
              <div key={i} style={styles.booking}>
                <div style={styles.dot}></div>
                <div>
                  <strong>{b.userName}</strong>
                  <p style={{ margin: 0, opacity: 0.6 }}>
                    {b.serviceName}
                  </p>
                </div>
              </div>
            ))
          )}
        </div>

      </div>
    </div>
  );
}

const styles = {
  page: {
    minHeight: "100vh",
    padding: "40px",
    background: "#0f172a", // 🔥 darker but not pure black
    color: "white",
    fontFamily: "Inter, sans-serif"
  },

  header: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    marginBottom: "30px"
  },

  title: {
    margin: 0,
    fontSize: "28px"
  },

  sub: {
    margin: 0,
    opacity: 0.6
  },

  logout: {
    padding: "10px 14px",
    borderRadius: "10px",
    border: "none",
    background: "#ef4444",
    color: "white",
    cursor: "pointer"
  },

  layout: {
    display: "grid",
    gridTemplateColumns: "1fr 1fr",
    gap: "20px"
  },

  panel: {
    background: "rgba(255,255,255,0.04)", // softer glass dark
    borderRadius: "16px",
    padding: "20px",
    border: "1px solid rgba(255,255,255,0.08)",
    backdropFilter: "blur(10px)"
  },

  heading: {
    marginBottom: "10px"
  },

  input: {
    width: "100%",
    padding: "12px",
    marginTop: "10px",
    borderRadius: "10px",
    border: "1px solid rgba(255,255,255,0.1)",
    background: "rgba(255,255,255,0.05)",
    color: "white",
    outline: "none"
  },

  grid: {
    display: "grid",
    gridTemplateColumns: "1fr 1fr",
    gap: "10px",
    marginTop: "15px"
  },

  card: {
    padding: "12px",
    borderRadius: "12px",
    cursor: "pointer",
    textAlign: "center",
    background: "rgba(255,255,255,0.03)"
  },

  button: {
    width: "100%",
    marginTop: "15px",
    padding: "12px",
    borderRadius: "10px",
    background: "#3b82f6",
    color: "white",
    border: "none",
    fontWeight: "bold",
    cursor: "pointer"
  },

  booking: {
    display: "flex",
    gap: "10px",
    padding: "10px",
    borderBottom: "1px solid rgba(255,255,255,0.08)"
  },

  dot: {
    width: "10px",
    height: "10px",
    background: "#3b82f6",
    borderRadius: "50%",
    marginTop: "6px"
  }
};

export default Booking;
